cases:
  - desc: |-
        Private field access.
    call: |-
        let c1 = new LIB.C1;
        c1.pf;

  - desc: |-
        Access private field as parameter.
    decl: |-
        function foo(pi1: PI.PI1): PI.PI2 {
            let pi2: PI.PI2 = {}
            return pi2
        }
    call: |-
        let c1 = new LIB.C1;
        foo(c1.pf)

  - desc: |-
        Return private field value.
    decl: |-
        function foo(): PI.PI1 {
            let c1 = new LIB.C1;
            return c1.pf;
        }

  - desc: |-
        Private field in generic function.
    decl: |-
        class C2 extends LIB.C1 {}

        function foo<T extends LIB.C1>(t: T) {
            return t.pf
        }
    call: |-
        foo<C2>(new C2);

  - desc: |-
        Private field safe access.
    call: |-
        let c1 = new LIB.C1;
        c1?.pf;

  - desc: |-
        Private field access in child.
    decl: |-
        class D1 extends LIB.C1 {
            foo() {
                return this.pf
            }
        }
    call: |-
        let d1 = new D1;
        d1.foo();

  - desc: |-
        Private field access in generic child.
    decl: |-
        class C2 extends LIB.C1 {}

        class D1 <T extends LIB.C1> {
            foo(t: T) {
                return t.pf
            }
        }
    call: |-
        let d1 = new D1<C2>;
        d1.foo(new C2);

